import networkx

def make_graph_from_edges(edges):
    """ Creates a Graph class given a list of edges. """
    G = networkx.Graph()
    G.add_edges_from(edges)
    return G

def make_graph_path(n=5):
    """ Creates a graph that is a path topology, with nodes in the natural integer order. """
    G = networkx.Graph()
    for i in range(1,n): G.add_edge(i,i+1)
    return G

