def assert_small_graphs_non_isomorphic(debugPrints=False):
    """ Sanity-check test to ensure no duplicate graphs. """
    for n in ALL_SMALL_GRAPHS:
        for i in range(len(ALL_SMALL_GRAPHS[n])):
            for j in range(i-1):
                assert not networkx.is_isomorphic(ALL_SMALL_GRAPHS[n][i],ALL_SMALL_GRAPHS[n][j])

def is_isomorphic_to_graph_in_list(g,list_of_graphs):
    """ Tests if the graph g is isomorphic to any of the graphs in the list. """
    for g2 in list_of_graphs:
        if networkx.is_isomorphic(g,g2): return True
    return False

def generate_all_trees_up_to(n, debugPrints=False):
    """ Programatically generates all trees up to n nodes. The edges are "jumbled" and may not have a canonical representation, e.g., the nodes of a path-graph may not be in the natural order.
    Can be used to generate more trees other than 'ALL_SMALL_GRAPHS' (n <= 8). However, Bigger trees are infeasible for other purposes. """
    graphs = [make_graph_path(3)] # Base case n=3, a single graph.
    ALL_GRAPHS = {3 : graphs[:]}
    for i in range(4,n+1):
        new_graphs = []
        for graph_to_extend in graphs:
            for k in range(1,i):
                new_graph = graph_to_extend.copy()
                new_graph.add_edge(i,k) # Adds a new node i, each time connected to a different existing node k.
                if not is_isomorphic_to_graph_in_list(new_graph,new_graphs): # Adds only if this graph is genuinely new.
                    new_graphs += [new_graph]
        graphs = new_graphs
        ALL_GRAPHS[i] = graphs[:]
        if debugPrints: print (i,len(graphs))
    return ALL_GRAPHS

class SearchTreeUtilities(object):
    """ The main class for useful utilities regarding trees and their STTs. This includes:
    Holding a graph and its size, a pre-computed map from pairs of nodes to the nodes between them, all possible STTs, and a mapping between the LP variable 'index' and 'names'. """
    
    def __init__(self,graph):
        self.G = graph.copy()
        self.n = len(self.G.nodes)
        
        self.pairs_oracle = {} # keys of the form (i,j) => values are lists of nodes between i and j.
        self._compute_graph_to_oracle()

        self._subgraph_memoization = {} # 'private' list of Graph objects used for memoization when computing all search trees.
        self._search_trees = None # Do not compute until it is first requested via 'self.get_all_search_trees()'.
        
        self.isBST = self._check_if_path()

        self.dict_ids_to_var_number = {} # Maps from 'ids' of variables to a running index that starts from 1, 0 is reserved.
        self.dict_var_number_to_ids = {} # The inverse map, from index to 'ids'. The ids of Xij and Zkij are tuples, (i,j) and (k,min(i,j),max(i,j)) respectively. The id of Di is i.
        self._construct_dictionaries_PRIMAL()
        self._construct_dictionaries_DUAL()
        
    def betweenNodes(self,i,j):
        """ Returns a list of all the nodes on the path between i and j. """
        a,b = min(i,j),max(i,j)
        if a not in self.G.nodes or b not in self.G.nodes: return [] # Nodes do not exist, consider as if disconnected.
        return self.pairs_oracle[(a,b)][:]

    def _check_if_path(self):
        """ Checks if the graph is a path over the nodes in natural order. """
        return set(self.G.edges()) == set([(i,i+1) for i in range(1,self.n)])
    
    def _compute_graph_to_oracle(self):
        """ Given a graph (networkx.Graph) object, with nodes names 1 to n, compute a dictionary that gets pairs of ids and returns the ids on the path between them. """
        self.pairs_oracle = {}
        d = networkx.all_pairs_shortest_path(self.G)
        for i, mapper in d:
            for j in mapper:
                if i < j:
                    path = mapper[j]
                    path.remove(i)
                    path.remove(j)
                    self.pairs_oracle[(i,j)] = path

    def _compute_all_search_trees(self,Graph):
        """ Given a graph (networkx.Graph) object, with nodes names 1 to n, compute a list of all the depths-vectors for possible search-trees over G. """
        key = tuple(sorted(Graph.nodes))
        if key in self._subgraph_memoization: # Memoization
            return self._subgraph_memoization[key]
        
        if len(Graph.nodes) == 1: # Induction base, single node => search tree with only a 0-depth root.
            G = Graph.copy()
            result = [-1]*self.n
            result[key[0]-1] = 0 # Indexed '-1' because nodes are named 1...n rather than 0...(n-1).
            self._subgraph_memoization[key] = [result]
            return self._subgraph_memoization[key]
        
        # else - recursive break-down. Consider each node as the root, and combine subtrees.
        result = []
        for node in Graph.nodes:
            G2 = Graph.copy()
            G2.remove_node(node)
            subtrees = []
            for component in networkx.connected_components(G2):
                H = G2.subgraph(component)
                subtrees += [self._compute_all_search_trees(H)]
            # Now combine the subtrees, in a cartesian manner.
            options = 1
            for s in subtrees: options *= len(s)
            for index in range(options):
                combination = cartesian_choice(subtrees, index)
                tree = [-1]*self.n
                tree[node-1] = 0 # root. Indexed '-1' because nodes are named 1...n rather than 0...(n-1).
                for t in combination:
                    for i in range(self.n):
                        if t[i] >= 0:
                            assert tree[i] == -1 # No overlaps.
                            tree[i] = t[i]+1 # +1 because we push down one level, due to the root.
                result += [tree]
        self._subgraph_memoization[key] = result
        return self._subgraph_memoization[key]

    def _construct_dictionaries_PRIMAL(self):
        """ Constructs two dictionaries to map between coordinates (variable number) and the variable's representation.
        Xs are determined by a pair (i,j) such that i != j. Zs are determined by triplets (k,i,j) where k is between i < j.
        Ds are determined by a single integer, their (node) name, starting from 1. The value of 0 is reserved for the free coefficient. """
        self.dict_ids_to_var_number = {}
        self.dict_var_number_to_ids = {}
        var_number = 1 # reserve 0 for the free coefficient.
        for i in range(1,self.n+1):
            for j in range(i+1,self.n+1):
                self.dict_ids_to_var_number[(i,j)] = var_number
                self.dict_var_number_to_ids[var_number] = (i,j)
                self.dict_ids_to_var_number[(j,i)] = var_number+1
                self.dict_var_number_to_ids[var_number+1] = (j,i)
                var_number += 2
                for k in self.betweenNodes(i,j):
                    self.dict_ids_to_var_number[(k,i,j)] = var_number
                    self.dict_var_number_to_ids[var_number] = (k,i,j)
                    var_number += 1
        for i in range(1,self.n+1): # Add the depth variables, for completeness.
            self.dict_ids_to_var_number[i] = var_number
            self.dict_var_number_to_ids[var_number] = i
            var_number += 1

    def _construct_dictionaries_DUAL(self):
        """ Constructs two dictionaries to map between coordinates (variable number) and the variable's representation.
        Rs are determined by a pair (i,j) such that i != j, and Rij===Rji.
        Qs are determined by a directed triplet (i,k,j) such that k is on the path from i to j. (Qikj != Qjki). """
        self.dict_ids_to_var_number_DUAL = {}
        self.dict_var_number_to_ids_DUAL = {}
        var_number = 1 # reserve 0 for the free coefficient.
        for i in range(1,self.n+1):
            for j in range(i+1,self.n+1):
                self.dict_ids_to_var_number_DUAL[(i,j)] = var_number
                self.dict_var_number_to_ids_DUAL[var_number] = (i,j)
                var_number += 1
                for k in self.betweenNodes(i,j):
                    self.dict_ids_to_var_number_DUAL[(i,k,j)] = var_number
                    self.dict_var_number_to_ids_DUAL[var_number] = (i,k,j)
                    self.dict_ids_to_var_number_DUAL[(j,k,i)] = var_number+1
                    self.dict_var_number_to_ids_DUAL[var_number+1] = (j,k,i)
                    var_number += 2

    def get_all_search_trees(self):
        """ Returns a list of all possible search trees. Computes it on the first call. """ 
        if self._search_trees is None:
            self._search_trees = [tuple(i) for i in self._compute_all_search_trees(self.G)] # a depths-vector for each possible search tree.
        return self._search_trees.copy()

    def find_best_search_tree(self, frequencies):
        """ Given frequences, return the best depths-vector for a search-tree over the topology.
        In general we just enumerate all possible trees. In the case of a path (BSTs), there is an efficient solution. """
        if self.isBST: return find_best_BST(frequencies)
        all_stts = self.get_all_search_trees() # else: naive enumeration.
        assert len(all_stts[0]) == len(frequencies) # sanity check
        return scalar_product_find_smallest(frequencies,all_stts)

    def is_stt(self, depths):
        """ Checks if a depths-vector represents a pure STT.
        Logic: (1) Ensure that all depths are integer. (2) Next, at each step ensure a single depth=0 node, which is the root. Remove it, decrease the depth of other nodes by 1, and repeat within each remaining connected component. """
        depths = list(depths) # In case the input is a tuple.
        if len(depths) == self.n: depths = [0] + depths # add a sentinel so that depth[i] is the depth of node i.
        if not is_integer_vector(depths): return False
        
        graph = self.G.copy()
        while len(graph.nodes) > 0:
            roots = [] # Keep all roots of current components, to be removed together.
            for comp in networkx.connected_components(graph):
                rs = [i for i in comp if depths[i] == 0]
                if len(rs) != 1: return False # No root, or more than one root.
                for i in comp: depths[i] -= 1 # Reduce the depth by 1 for the next iteration.
                roots += rs # We delete all the roots together.
            graph.remove_nodes_from(roots)
        return True

    def stt_to_XZD_vector(self, stt_depths):
        """ Given an STT as a depths-vector, compute its induced coordinates in XZD space. (assumes correct input, use 'is_stt' to verify that the input is an STT.)
        Recall the interpretation: Xij=1 if i is an ancestor of j, Zkij=1 if k=LCA(i,j) and Di is the number of strict ancestors of i, i.e. D(root)=0. """
        assert self.n == len(stt_depths)
        depths = [0] + list(stt_depths) # sentinel for simpler indexing.
        
        mapper = self.dict_ids_to_var_number # shortening
        XZD_vec = [0] * (len(mapper) + 1) # index-0 is a sentinel to be removed in the end.

        for i in range(1,self.n+1):
            XZD_vec[mapper[i]] = depths[i] # D variables        
            for j in range(i+1,self.n+1):
                Xij,Xji = mapper[(i,j)],mapper[(j,i)]
                XZD_vec[Xij],XZD_vec[Xji] = 0,0 # X variables, we may fix one of these later

                LCA_candidates = self.betweenNodes(i,j) + [i,j]
                LCA_depths = [depths[k] for k in LCA_candidates]
                min_d = min(LCA_depths)
                assert LCA_depths.count(min_d) == 1 # Unique minimal-depth on the path
                lca = LCA_candidates[LCA_depths.index(min_d)]

                for k in LCA_candidates:
                    if k not in [i,j]:
                        Zkij = mapper[(k,i,j)] # Z variables
                        XZD_vec[Zkij] = (1 if k == lca else 0)
                    else:
                        if lca == i: XZD_vec[Xij] = 1
                        if lca == j: XZD_vec[Xji] = 1

        return XZD_vec[1:] # Remove the sentinel.

    def stt_to_X_matrix(self, stt_depths):
        """ Given an STT (depths) on the topology, return a matrix X such that Xij=1 if i is an ancestor of j, 0 otherwise. """
        X = [[0]*self.n for i in range(self.n)]
        for i in range(1,self.n+1):
            for j in range(1,i): # Ensures we skip i=j (since Xii=0).
                minDepthIJ = min(stt_depths[i-1],stt_depths[j-1])
                depthsBetween = [stt_depths[k-1] for k in self.betweenNodes(i,j)]
                if len(depthsBetween) >= 1 and min(depthsBetween) < minDepthIJ: continue # Some LCA separates i and j.
                if stt_depths[i-1] < stt_depths[j-1]:
                    X[i-1][j-1] = 1
                else:
                    X[j-1][i-1] = 1
        return X

    def lifting(self, X, new_root):
        """ Given X variables, and a new root, we 'lift' the new root above other nodes such that its relation to any other node is 1<->0, and the relation between nodes on different sides of it is 0<->0. """
        new_X = {}
        for i in range(1,self.n+1):
            if i == new_root: continue
            new_X[(new_root,i)],new_X[(i,new_root)] = 1,0
            
            for j in range(1,i):
                if j == new_root: continue
                if new_root in self.betweenNodes(i,j): new_X[(j,i)],new_X[(i,j)] = 0,0
                else:                                  new_X[(j,i)],new_X[(i,j)] = X[(j,i)],X[(i,j)] # Unaffected.
        return new_X

def find_best_BST(frequencies):
    """ Computes the best BST (depths vector) for a given direction. Using dynamic programming, like Knuth's algorithm, but simpler implementation in O(n^3) rather than O(n^2). """
    n = len(frequencies)

    # dynamic-programming to find the best tree
    map_roots,map_costs,map_total_frequencies = {},{},{}
    for i in range(n):
        map_roots[(i,i)] = i
        map_costs[(i,i)] = frequencies[i]
        map_total_frequencies[(i,i)] = frequencies[i]
        
    for segment_size in range(2,n+1):
        for i in range(n):
            j = i + segment_size - 1
            if j > n-1: # out of range
                continue

            frequency_ItoJ = frequencies[i] + map_total_frequencies[(i+1,j)] # agnostic to the choice of root so we compute it once
            
            # Start with the edge cases of empty subtree, then loop over middle roots.
            best_root,best_cost = i,map_costs[(i+1,j)]
            if map_costs[(i+1,j)] > map_costs[(i,j-1)]:
                best_root,best_cost = j,map_costs[(i,j-1)]
            for k in range(i+1,j):
                cost = map_costs[(i,k-1)] + map_costs[(k+1,j)]
                if cost < best_cost:
                    best_root,best_cost = k,cost
            map_roots[(i,j)] = best_root
            map_costs[(i,j)] = best_cost + frequency_ItoJ # we add 'frequency_ItoJ' to the cost because everything pays 1 extra (including the root which paid 0 when we looped).
            map_total_frequencies[i,j] = frequency_ItoJ

    # Determine the tree from the choice of roots in each sub-problem.
    def _set_depth(mapper,segment,inplace_vector,depth):
        a,b = segment
        root = mapper[(a,b)]
        inplace_vector[root] = depth
        if a==b: return # recursion base.
        if root < b:
            _set_depth(mapper,(root+1,b),inplace_vector,depth+1)
        if root > a:
            _set_depth(mapper,(a,root-1),inplace_vector,depth+1)

    depths = [-1]*n
    _set_depth(map_roots,(0,n-1),depths,0)
    return tuple(depths)

def round_to_STT(x_variables, graph, isFirstCall=True):
    """ Takes a dictionary of X variables of the form x_variables(i,j)= Xij, and computes STT depth vectors according to Golinsky's rounding scheme.
    We return a list of all possible roundings, in case multiple options apply. """
    global rounding_subgraph_memoization
    
    if isFirstCall:
        rounding_subgraph_memoization = {}
        
    key = tuple(sorted(graph.nodes))
    if key in rounding_subgraph_memoization: # Memoization
        if isFirstCall: raise Exception("Impossible, we just initialized the memoization dictionary.")
        return rounding_subgraph_memoization[key]

    if len(graph.nodes) == 1:
        firstNode = [i for i in graph.nodes][0]
        rounding_subgraph_memoization[key] = [{firstNode: 0}]
        if isFirstCall: raise Exception("Should not call this function on a graph with a single node!")
        return rounding_subgraph_memoization[key] #single-node tree.
        
    searchTreeUtilities = SearchTreeUtilities(graph)
    result = []
    
    for r in graph.nodes:
        R = [0]*(max(graph.nodes) + 1) # Lazy, but not too wasteful in memory.
        for v in graph.nodes:
            for u in graph.nodes:
                if u != v and (r == u or r in searchTreeUtilities.betweenNodes(u,v)):
                    R[v] += x_variables[(u,v)]

        actualR = [R[i] for i in range(len(R)) if i in graph.nodes and i != r]
        if min(actualR) >= 0.5 - NUMERIC_ERROR: # r is a possible root.
            g2 = graph.copy()
            g2.remove_node(r)
            subtrees = []
            for component in networkx.connected_components(g2):
                h = g2.subgraph(component)
                subtrees += [round_to_STT(x_variables, h, False)]

            # Now combine the subtrees, in a cartesian manner.
            options = 1
            for s in subtrees: options *= len(s)
            for index in range(options):
                combination = cartesian_choice(subtrees, index)
                tree = {r : 0} # root
                for subtree in combination:
                    for k in subtree:
                        tree[k] = subtree[k]+1
                assert len(tree) == searchTreeUtilities.n
                result += [tree]

    rounding_subgraph_memoization[key] = result

    if isFirstCall: # Return the result in a format of tuples rather than dictionaries.
        return [tuple([r[k] for k in range(1,searchTreeUtilities.n+1)]) for r in rounding_subgraph_memoization[key]]
    return rounding_subgraph_memoization[key]

def dedup_automorphism_vertices(vertex_dict):
    """ Remove vectors (vertices or directions) that are equivalent to others due to graph automorphism. The input should be a dictionary that maps from graph name-tuples '(n,i)' to a list of vectors (e.g. vertices). """
    vertex_dict_uniques = {}
    for n,i in vertex_dict:
        g = ALL_SMALL_GRAPHS[n][i]
        all_automorphisms = [i for i in networkx.algorithms.isomorphism.GraphMatcher(g,g).isomorphisms_iter()] # Dealing with small graphs, it is fine to just produce the whole list at-once.
        vertices = set(vertex_dict[(n,i)])
        uniques = []
        while len(vertices) > 0:
            v = vertices.pop()
            uniques += [v]
            for auto in all_automorphisms:
                new_v = [0]*len(v)
                for idx in auto: new_v[auto[idx]-1] = v[idx-1]
                if tuple(new_v) in vertices: vertices.remove(tuple(new_v))
            vertex_dict_uniques[(n,i)] = uniques[:]
    return vertex_dict_uniques

def extend_dict_of_depths_to_full_vertices(vertex_dict, printMultipleExtensions=False):
    extended_dict = {}
    for key in vertex_dict:
        n,idx = key
        extended_dict[key] = []
        searchTreeUtilities = SearchTreeUtilities(ALL_SMALL_GRAPHS[n][idx])
        for v in vertex_dict[key]:
            extensions = [vfull for vfull in MAPPER_INDEX_TO_FULL_VERTEX[key] if tuple(vfull[-n:]) == v]
            assert len(extensions) >= 1 # At least one extension, from which we derived the depths in the first place
            extended_dict[key] += [(tuple(v),tuple(sorted(extensions)[-1]))] # sorting for consistency
            if printMultipleExtensions and len(extensions) > 1:
                print ("Topology: %s | depths-vector = %s | #extensions = %d"%(str(key),str(v),len(extensions)))
                for e in extensions:
                    print_XZD_solution(e,searchTreeUtilities.n,searchTreeUtilities.dict_ids_to_var_number)
    return extended_dict

NON_INT_VERTICES_REDUCED = dedup_automorphism_vertices(vertex_dict = NON_INT_VERTICES)
NON_INT_VERTICES_REDUCED_WHOLE_REPRESENTATION = extend_dict_of_depths_to_full_vertices(NON_INT_VERTICES_REDUCED,False)


